6	
7	#include <uhd/exception.hpp>
8	#include <uhd/rfnoc/mb_controller.hpp>
9	#include <uhd/utils/algorithm.hpp>
10	#include <uhd/utils/log.hpp>
11	#include <boost/format.hpp>
12	#include <atomic>
13	#include <chrono>
14	#include <future>
15	#include <thread>
16	#include <tuple>
17	
18	using namespace uhd::rfnoc;
19	using namespace std::chrono_literals;
20	
21	namespace {
22	const std::vector<std::string> SYNCHRONIZABLE_REF_SOURCES = {"gpsdo", "external"};
23	
24	/*! Synchronize a list of timekeepers
25	 *
26	 * Function is agnostic to the owning motherboard and works either
27	 * on a single device/motherboard or accross multiple devices/motherboards.
28	 *
29	 * \param timekeepers A list of timekeepers to synchronize.
30	 * \param timespec    Time specification to synchronize \p timekeepers to.
31	 * \param quiet       If true, don't print errors or warnings
32	 *                    if synchronization fails
33	 * \returns true if all timekeepers that were listed on \p timekeepers
34	 *               could be synchronized.
35	 *
36	 */
37	bool sync_tks(
38	    std::vector<std::tuple<size_t, size_t, uhd::rfnoc::mb_controller::timekeeper::sptr>>
39	        timekeepers,
40	    const uhd::time_spec_t time_spec,
41	    const bool quiet)
42	{
43	    if (!quiet) {
44	        UHD_LOGGER_INFO("MB_CTRL")
45	            << "Synchronizing " << timekeepers.size() << " timekeepers";
46	    } else {
47	        UHD_LOGGER_DEBUG("MB_CTRL")
48	            << "Synchronizing " << timekeepers.size() << " timekeepers";
49	    }
50	
51	    // The best way to synchronize timekeepers depends on how many devices and
52	    // how many timekeepers per device we have. Here, we handle two different
53	    // cases:
54	    // Case 1: Single device, single timekeeper, no need to sync to PPS
55	    if (timekeepers.size() == 1) {
56	        std::get<2>(timekeepers.front())->set_time_now(time_spec);
57	        return true;
58	    }
59	
60	    // Case 2: We have multiple timekeepers. To sync them, we need to use PPS.
61	    if (!quiet) {
62	        UHD_LOGGER_INFO("MB_CTRL")
63	            << "  Synchronizing timekeepers to Board " << std::get<0>(timekeepers.front())
64	            << "/TK " << std::get<1>(timekeepers.front());
65	        UHD_LOGGER_INFO("MB_CTRL") << "    1) catch time transition at pps edge";
66	    }
67	    const auto end_time = std::chrono::steady_clock::now() + 1100ms;
68	    const uhd::time_spec_t time_start_last_pps =
69	        std::get<2>(timekeepers.front())->get_time_last_pps();
70	    while (time_start_last_pps == std::get<2>(timekeepers.front())->get_time_last_pps()) {
71	        if (std::chrono::steady_clock::now() > end_time) {
72	            // This is always bad, and we'll throw regardless of quiet
73	            throw uhd::runtime_error("Board "
74	                                     + std::to_string(std::get<0>(timekeepers.front()))
75	                                     + " may not be getting a PPS signal!\n"
76	                                       "No PPS detected within the time interval.\n"
77	                                       "See the application notes for your device.\n");
78	        }
79	        std::this_thread::sleep_for(1ms);
80	    }
81	
82	    if (!quiet) {
83	        UHD_LOGGER_INFO("MB_CTRL") << "    2) set times next pps (synchronously)";
84	    }
85	
86	    for (auto& timekeeper : timekeepers) {
87	        std::get<2>(timekeeper)->set_time_next_pps(time_spec);
88	    }
89	    std::this_thread::sleep_for(1s);
90	
91	    // verify that the time registers are read to be within a few RTT
92	    for (auto& timekeeper : timekeepers) {
93	        size_t mb_idx, tk_idx;
94	        uhd::rfnoc::mb_controller::timekeeper::sptr tk;
95	        std::tie(mb_idx, tk_idx, tk) = timekeeper;
96	
97	        uhd::time_spec_t time_0 = std::get<2>(timekeepers.front())->get_time_now();
98	        uhd::time_spec_t time_i = tk->get_time_now();
99	        // 10 ms: greater than RTT but not too big
100	        constexpr double MAX_DEVIATION = 0.01;
101	        if (time_i < time_0 or (time_i - time_0) > uhd::time_spec_t(MAX_DEVIATION)) {
102	            const auto warn_str = str(
103	                boost::format(
104	                    "Detected time deviation between board %1%/TK %2% and board %5%.\n"
105	                    "Board %5%/TK %6% time is %3% seconds.\n"
106	                    "Board %1%/TK %2% time is %4% seconds.\n")
107	                % mb_idx % tk_idx % time_0.get_real_secs() % time_i.get_real_secs()
108	                % std::get<0>(timekeepers.front()) % std::get<1>(timekeepers.front()));
109	
110	            if (!quiet) {
111	                UHD_LOG_WARNING("MB_CTRL", warn_str);
112	            } else {
113	                UHD_LOG_DEBUG("MB_CTRL", warn_str);
114	            }
115	            return false;
116	        }
117	    }
118	    return true;
119	}
120	
121	
122	} // namespace
123	
124	bool mb_controller::synchronize(std::vector<mb_controller::sptr>& mb_controllers,
125	    const uhd::time_spec_t& time_spec,
126	    const bool quiet)
127	{
128	    if (mb_controllers.empty()) {
129	        return false;
130	    }
131	    // Verify that all devices share a time reference, and that it is a common
132	    // one
133	    const std::string time_source = mb_controllers.at(0)->get_time_source();
134	    if (!uhd::has(SYNCHRONIZABLE_REF_SOURCES, time_source) && mb_controllers.size() > 1
135	        && !quiet) {
136	        UHD_LOG_WARNING("MB_CTRL",
137	            "The selected time source "
138	                << time_source << " does not allow synchronization between devices.");
139	    }
140	    for (auto& mbc : mb_controllers) {
